{
  "sentences": [
    {
      "text": "你是不是說錯的意思？",
      "pinyin": "Nǐ shì bù shì shuō cuò de yìsi?",
      "pinyin_numeric": "ni3 shi4 bu4 shi4 shuo1 cuo4 de0 yi4si0",
      "translation_en": "Is it that you said it wrong?",
      "translation_ko": "당신이 잘못 말했다는 뜻인가요?"
    },
    {
      "text": "他是不是誤會我的意思？",
      "pinyin": "Tā shì bù shì wùhuì wǒ de yìsi?",
      "pinyin_numeric": "ta1 shi4 bu4 shi4 wu4hui4 wo3 de0 yi4si0",
      "translation_en": "Is it that he misunderstood me?",
      "translation_ko": "그가 제 뜻을 오해한 건가요?"
    },
    {
      "text": "你是不是以為我生氣的？",
      "pinyin": "Nǐ shì bù shì yǐwéi wǒ shēngqì de?",
      "pinyin_numeric": "ni3 shi4 bu4 shi4 yi3wei2 wo3 sheng1qi4 de0",
      "translation_en": "Is it that you thought I was angry?",
      "translation_ko": "당신은 제가 화난 줄 알았나요?"
    },
    {
      "text": "這個句子是不是有錯誤的意思？",
      "pinyin": "Zhège jùzi shì bù shì yǒu cuòwù de yìsi?",
      "pinyin_numeric": "zhe4ge0 ju4zi0 shi4 bu4 shi4 you3 cuo4wu4 de0 yi4si0",
      "translation_en": "Is it that this sentence has a wrong meaning?",
      "translation_ko": "이 문장이 잘못된 뜻을 가지고 있나요?"
    },
    {
      "text": "你的答案是不是不對的意思？",
      "pinyin": "Nǐ de dá'àn shì bù shì bù duì de yìsi?",
      "pinyin_numeric": "ni3 de0 da2'an4 shi4 bu4 shi4 bu4 dui4 de0 yi4si0",
      "translation_en": "Is it that your answer is incorrect?",
      "translation_ko": "당신의 답이 틀렸다는 뜻인가요?"
    },
    {
      "text": "他是不是需要解釋清楚的意思？",
      "pinyin": "Tā shì bù shì xūyào jiěshì qīngchu de yìsi?",
      "pinyin_numeric": "ta1 shi4 bu4 shi4 xu1yao4 jie3shi4 qing1chu0 de0 yi4si0",
      "translation_en": "Is it that he needs to explain clearly?",
      "translation_ko": "그가 명확하게 설명해야 한다는 뜻인가요?"
    },
    {
      "text": "你是不是想改答案的意思？",
      "pinyin": "Nǐ shì bù shì xiǎng gǎi dá'àn de yìsi?",
      "pinyin_numeric": "ni3 shi4 bu4 shi4 xiang3 gai3 da2'an4 de0 yi4si0",
      "translation_en": "Is it that you want to change the answer?",
      "translation_ko": "당신이 답을 바꾸고 싶다는 뜻인가요?"
    },
    {
      "text": "我們是不是誤會他的意思？",
      "pinyin": "Wǒmen shì bù shì wùhuì tā de yìsi?",
      "pinyin_numeric": "wo3men0 shi4 bu4 shi4 wu4hui4 ta1 de0 yi4si0",
      "translation_en": "Is it that we misunderstood him?",
      "translation_ko": "우리가 그를 오해한 건가요?"
    },
    {
      "text": "這個問題是不是沒有正確答案的意思？",
      "pinyin": "Zhège wèntí shì bù shì méiyǒu zhèngquè dá'àn de yìsi?",
      "pinyin_numeric": "zhe4ge0 wen4ti2 shi4 bu4 shi4 mei2you3 zheng4que4 da2'an4 de0 yi4si0",
      "translation_en": "Is it that this question has no correct answer?",
      "translation_ko": "이 문제에 정답이 없다는 뜻인가요?"
    },
    {
      "text": "你說的「算了」是不是放棄的意思？",
      "pinyin": "Nǐ shuō de 'suàn le' shì bù shì fàngqì de yìsi?",
      "pinyin_numeric": "ni3 shuo1 de0 'suan4 le0' shi4 bu4 shi4 fang4qi4 de0 yi4si0",
      "translation_en": "Is it that the 'forget it' you said means giving up?",
      "translation_ko": "당신이 말한 '됐어'가 포기한다는 뜻인가요?"
    }
  ]
}
